const flags = $('Prepare Retrieval').first().json || {};
const n = $('Normalize Input').first().json || {};
const question = n.question || '';
const history = Array.isArray(n.history) ? n.history : [];
const NL = String.fromCharCode(10);
const historyText = history.map(m => (m.role === 'assistant' ? 'Assistant: ' : 'User: ') + (m.content || '')).join(NL);
const TOPK = 20;

const rows = [];
const all = $input.all();
for (let i = 0; i < all.length; i++) {
  const j = all[i].json || {};
  if (j.isChatDoc === true) {
    rows.push({ text: String(j.text || '').slice(0, 100000), filename: j.filename || '', isLibrary: false });
  } else if (j.driveFileId && j.text != null) {
    rows.push({ text: String(j.text).slice(0, 24000), filename: j.filename || '', isLibrary: true, origin: j.origin, driveFileId: j.driveFileId });
  }
}
const chat = rows.filter(r => !r.isLibrary);
const lib = rows.filter(r => r.isLibrary);

// Use everything gathered: per-chat docs plus any Drive/Library results. Dedup
// identical rows (a lookup can return the same file more than once).
let chosen = chat.concat(lib);
const seen = new Set();
chosen = chosen.filter(r => { const k = (r.filename || '') + '#' + (r.text || '').slice(0, 60); if (seen.has(k)) return false; seen.add(k); return true; }).slice(0, TOPK);

const sources = [], contextParts = [];
for (const r of chosen) {
  const origin = r.origin || (r.isLibrary ? 'Drive' : 'This chat');
  contextParts.push('[' + (contextParts.length + 1) + '] (' + origin + ' · ' + r.filename + ') ' + r.text);
  sources.push({ filename: r.filename, chunkIndex: 0, text: r.text, origin, driveFileId: r.driveFileId });
}
return [{ json: { question, context: contextParts.length ? contextParts.join(NL + NL) : '', sources, historyText } }];

const j = $input.first().json || {};
let answer = '';
if (j.text != null) { answer = j.text; }
else if (j.output != null) { answer = j.output; }
else if (j.response != null) { answer = j.response; }
const sources = ($('Assemble Final').first().json.sources) || [];
return [{ json: { answer: answer, sources: sources } }];

let useDrive = false;
let webSearch = false;
const c = $input.first().json;
const content = (c && c.choices && c.choices[0] && c.choices[0].message && c.choices[0].message.content) || '';
const s = String(content); const a = s.indexOf('{'); const b = s.lastIndexOf('}');
if (a >= 0 && b > a) { try { const o = JSON.parse(s.slice(a, b + 1)); useDrive = o.useDrive === true; webSearch = o.webSearch === true; } catch (e) {} }
const n = $('Normalize Input').first().json;
const hasFile = Array.isArray(n.docs) && n.docs.length > 0;
return [{ json: { conversationId: n.conversationId, question: n.question, history: n.history, hasFile: hasFile, useDrive: useDrive, webSearch: webSearch, skipDrive: n.skipDrive === true } }];

const n = $('Normalize Input').first().json || {};
const docs = n.docs || [];
const lib = n.libraryDocs || [];
const rows = docs.map(d => ({ json: { filename: d.filename || '', text: d.text || '', isChatDoc: true } }));
lib.forEach((d, i) => rows.push({ json: { driveFileId: 'library:' + i, filename: d.filename || '', text: d.text || '', isLibrary: true, origin: 'Library' } }));
// Always emit at least one item (a placeholder Build Context ignores) so the
// merge -> context -> answer chain still runs when there is nothing attached.
return rows.length ? rows : [{ json: { placeholder: true } }];

const r = $input.first().json || {};
const out = Array.isArray(r.output) ? r.output : [];
let atext = '';
const raw = [];
for (const o of out) {
  if (o && o.type === 'message' && Array.isArray(o.content)) {
    for (const c of o.content) {
      if (c && (c.type === 'output_text' || typeof c.text === 'string')) {
        const base = atext.length;
        atext += (c.text || '');
        const a2 = Array.isArray(c.annotations) ? c.annotations : [];
        for (const a of a2) {
          if (a && a.type === 'url_citation' && a.url) {
            const p = (typeof a.start_index === 'number') ? a.start_index : ((typeof a.end_index === 'number') ? a.end_index : 0);
            raw.push({ url: a.url, title: a.title || '', pos: base + p });
          }
        }
      }
    }
  }
}
const linkRe = /\[([^\]]{1,120})\]\((https?:\/\/[^)\s]+)\)/g;
let mm;
while ((mm = linkRe.exec(atext)) !== null) { raw.push({ url: mm[2], title: mm[1], pos: mm.index }); }
function stripMd(s) { return (s || '').replace(/\[([^\]]{1,120})\]\((https?:\/\/[^)\s]+)\)/g, '$1'); }
function host(u) { const m = String(u || '').match(/^https?:\/\/([^\/?#]+)/i); return m ? m[1].toLowerCase() : ''; }
// Strip utm_* tracking params (e.g. ?utm_source=openai) from a URL.
function cleanUrl(u) {
  u = String(u || '');
  let hash = '';
  const hi = u.indexOf('#');
  if (hi >= 0) { hash = u.slice(hi); u = u.slice(0, hi); }
  const qi = u.indexOf('?');
  if (qi < 0) return u + hash;
  const base = u.slice(0, qi);
  const kept = u.slice(qi + 1).split('&').filter(function(p){ return p && !/^utm_/i.test(p); });
  return base + (kept.length ? ('?' + kept.join('&')) : '') + hash;
}
const BLOCK = ['about.me','pinterest.','facebook.com','instagram.com','quora.com','reddit.com','tiktok.com','scribd.com','coursehero.com'];
function blocked(u) { const h = host(u); return !h || BLOCK.some(function(b){ return h.indexOf(b) !== -1; }); }
const byKey = new Map();
const order = [];
for (const a of raw) {
  if (blocked(a.url)) continue;
  const key = a.url.split('?')[0];
  if (!byKey.has(key)) { byKey.set(key, { url: a.url, title: a.title || host(a.url), pos: a.pos }); order.push(key); }
}
const uniq = order.map(function(k){ return byKey.get(k); });
const NL = String.fromCharCode(10);
for (const c of uniq) {
  const seg = stripMd(atext.slice(Math.max(0, c.pos - 240), c.pos)).replace(/\s+/g, ' ').trim();
  c.snippet = seg.slice(-260) || c.title;
}
const bc = $('Build Context and Sources').first().json || {};
const directive = 'PETUNJUK: Konteks di bawah berasal dari PENCARIAN WEB, bukan dokumen milik pengguna. Sampaikan sebagai hasil pencarian web (mis. "berdasarkan hasil pencarian web"), sertakan penanda [n] sesuai nomor sumber, dan JANGAN menyebutnya "dokumen" atau file pengguna. Jangan menyalin petunjuk ini ke jawaban.';
let context, sources;
if (uniq.length) {
  const parts = uniq.map(function(c, i){ return '[' + (i + 1) + '] (Web · ' + c.title + ') ' + (c.snippet || c.title); });
  context = directive + NL + NL + parts.join(NL + NL);
  sources = uniq.map(function(c, i){ return { filename: c.title, chunkIndex: i, text: c.snippet || '', origin: 'Web', webUrl: cleanUrl(c.url) }; });
} else {
  const clean = stripMd(atext).replace(/\s+/g, ' ').trim();
  context = clean ? (directive + NL + NL + '[Hasil pencarian web]' + NL + clean) : (bc.context || '');
  sources = [];
}
return [{ json: { question: bc.question || '', historyText: bc.historyText || '', context: context, sources: sources } }];

// Deterministic grounding guard: reached only when a Drive/document lookup
// returned no context and no file was attached. Return an honest 'not found'
// message instead of letting the LLM invent document content.
const j = $input.first().json || {};
const q = String(j.question || '').toLowerCase();
const idMarkers = ['apa','apakah','siapa','berapa','kapan','mengapa','kenapa','bagaimana','yang','dari','dengan','untuk','pada','dalam','berdasarkan','bedasarkan','tolong','jelaskan','dinas','dokumen','saya','ini','itu','dan','atau'];
const isID = idMarkers.some(function(w){ return new RegExp('\\b' + w + '\\b').test(q); });
const msg = isID
  ? 'Maaf, saya tidak menemukan file atau data yang cocok di Google Drive Anda untuk menjawab pertanyaan ini. Coba periksa nama filenya, pastikan file tersebut ada di folder yang terhubung, atau lampirkan filenya langsung ke chat ini agar saya bisa membacanya (termasuk PDF hasil scan/gambar).'
  : "I couldn't find a matching file or data in your Google Drive to answer this. Please check the file name, make sure it is in the connected folder, or attach the file directly to this chat so I can read it (including scanned/image PDFs).";
return [{ json: { text: msg } }];
